add_action('wp_ajax_petshop_search_products', function() {
    check_ajax_referer('petshop_rinkinio_nonce', 'nonce');
    $term = sanitize_text_field($_GET['term'] ?? '');
    if (strlen($term) < 2) { wp_send_json([]); return; }

    $args = array(
        'post_type' => 'product',
        'post_status' => 'publish',
        's' => $term,
        'posts_per_page' => 20,
        'tax_query' => array(
            array(
                'taxonomy' => 'product_type',
                'field' => 'slug',
                'terms' => array('simple'),
            ),
        ),
    );
    // Taip pat ieškom pagal SKU
    $by_sku = wc_get_product_id_by_sku($term);

    $query = new WP_Query($args);
    $results = array();
    $seen = array();

    // Pirma SKU match
    if ($by_sku) {
        $p = wc_get_product($by_sku);
        if ($p && $p->get_status() === 'publish' && $p->is_type('simple')) {
            $img = wp_get_attachment_image_url($p->get_image_id(), 'thumbnail') ?: '';
            $results[] = array(
                'id' => $p->get_id(),
                'text' => $p->get_name() . ' (SKU: ' . $p->get_sku() . ')',
                'price' => $p->get_price(),
                'stock' => $p->get_stock_quantity(),
                'stock_status' => $p->get_stock_status(),
                'image' => $img,
            );
            $seen[$by_sku] = true;
        }
    }

    if ($query->have_posts()) {
        while ($query->have_posts()) {
            $query->the_post();
            $pid = get_the_ID();
            if (isset($seen[$pid])) continue;
            $p = wc_get_product($pid);
            if (!$p) continue;
            $img = wp_get_attachment_image_url($p->get_image_id(), 'thumbnail') ?: '';
            $results[] = array(
                'id' => $p->get_id(),
                'text' => $p->get_name() . ' (SKU: ' . $p->get_sku() . ')',
                'price' => $p->get_price(),
                'stock' => $p->get_stock_quantity(),
                'stock_status' => $p->get_stock_status(),
                'image' => $img,
            );
        }
        wp_reset_postdata();
    }
    wp_send_json($results);
});

