add_action('wp_ajax_petshop_create_bundle', function() {
    check_ajax_referer('petshop_rinkinio_nonce', 'nonce');

    if (!current_user_can('manage_woocommerce')) {
        wp_send_json_error('Neturite teisių.');
        return;
    }

    $data = json_decode(stripslashes($_POST['bundle_data'] ?? ''), true);
    if (!$data) { wp_send_json_error('Neteisingi duomenys.'); return; }

    $title = sanitize_text_field($data['title'] ?? '');
    $sku = sanitize_text_field($data['sku'] ?? '');
    $price = floatval($data['price'] ?? 0);
    $category_slug = sanitize_text_field($data['category'] ?? '');
    $short_desc = sanitize_textarea_field($data['short_description'] ?? '');
    $components = $data['components'] ?? array();

    // Validacija
    $errors = array();
    if (empty($title)) $errors[] = 'Trūksta pavadinimo.';
    if (empty($sku)) $errors[] = 'Trūksta SKU.';
    if ($price <= 0) $errors[] = 'Kaina turi būti teigiama.';
    if (empty($components)) $errors[] = 'Pridėkite bent vieną komponentą.';
    if (wc_get_product_id_by_sku($sku)) $errors[] = 'SKU "' . $sku . '" jau egzistuoja.';

    // Apskaičiuojam bendrą kiekį
    $total_qty = 0;
    $comp_quantities = array();
    foreach ($components as $c) {
        $cid = intval($c['id'] ?? 0);
        $qty = intval($c['qty'] ?? 1);
        if ($cid <= 0) { $errors[] = 'Neteisingas komponento ID.'; continue; }
        if ($qty < 1) $qty = 1;
        $total_qty += $qty;
        $comp_quantities[$cid] = $qty;
    }

    if (!empty($errors)) { wp_send_json_error(implode(' ', $errors)); return; }

    // Kategorija
    $cat_term = get_term_by('slug', $category_slug, 'product_cat');
    if (!$cat_term) { wp_send_json_error('Kategorija "' . $category_slug . '" nerasta.'); return; }

    // Generuojam aprašymą
    $is_konservai = ($category_slug === 'konservu-rinkiniai');
    $unit = $is_konservai ? 'skardinės' : 'vnt.';
    $desc_html = '<h3>Rinkinyje rasite (' . $total_qty . ' ' . $unit . '):</h3>' . "\n<ol>\n";
    foreach ($components as $c) {
        $cp = wc_get_product(intval($c['id']));
        if (!$cp) continue;
        $qty = intval($c['qty'] ?? 1);
        $prefix = $qty > 1 ? ($qty . ' × ') : '';
        $desc_html .= '  <li>' . $prefix . esc_html($cp->get_name()) . "</li>\n";
    }
    $desc_html .= "</ol>\n";
    if ($is_konservai) {
        $desc_html .= '<p><em>Gyvūnas visuomet turi turėti šviežio geriamo vandens.</em></p>';
    }

    // === SUKURIAM MnM PRODUKTĄ ===
    try {
        $product = new WC_Product_Mix_and_Match();
        $product->set_name($title);
        $product->set_sku($sku);
        $product->set_status('publish');
        $product->set_catalog_visibility('visible');
        $product->set_price($price);
        $product->set_regular_price($price);
        $product->set_short_description($short_desc);
        $product->set_description($desc_html);
        $product->set_sold_individually(false);
        $product->set_category_ids(array($cat_term->term_id));

        // MnM specifiniai laukai
        $product->set_min_container_size($total_qty);
        $product->set_max_container_size($total_qty);
        $product->update_meta_data('_mnm_content_source', 'products');
        $product->update_meta_data('_mnm_per_product_pricing', 'no');

        // Per-komponentiniai kiekiai (mūsų custom meta)
        $product->update_meta_data('_petshop_component_quantities', wp_json_encode($comp_quantities));

        $product->save();
        $product_id = $product->get_id();

        if (!$product_id) {
            wp_send_json_error('Nepavyko sukurti produkto.');
            return;
        }

        // Pridedame child items per DB tiesiogiai (MnM API)
        global $wpdb;
        $table = $wpdb->prefix . 'wc_mnm_child_items';
        $order = 0;
        foreach ($components as $c) {
            $cid = intval($c['id']);
            $order++;
            $wpdb->insert($table, array(
                'product_id' => $cid,
                'container_id' => $product_id,
                'menu_order' => $order,
            ), array('%d', '%d', '%d'));
        }

        // === KOMPOZICIJOS GENERAVIMAS (PHP GD) ===
        $comp_image_result = petshop_generate_composition($product_id, $components);

        wp_send_json_success(array(
            'product_id' => $product_id,
            'edit_url' => admin_url('post.php?post=' . $product_id . '&action=edit'),
            'view_url' => get_permalink($product_id),
            'composition' => $comp_image_result,
            'total_qty' => $total_qty,
        ));

    } catch (Exception $e) {
        wp_send_json_error('Klaida kuriant: ' . $e->getMessage());
    }
});

