// 4. KOMPOZICIJOS GENERAVIMAS (PHP GD)
// ============================================================
function petshop_generate_composition($product_id, $components) {
    $tile_size = 380;
    $gap = 30;
    $padding = 30;
    $bg_color_rgb = array(248, 248, 248);
    $tile_bg_rgb = array(255, 255, 255);

    // Surenkam nuotraukas (unikalios)
    $images = array();
    $seen = array();
    foreach ($components as $c) {
        $cid = intval($c['id']);
        if (isset($seen[$cid])) continue;
        $seen[$cid] = true;
        $cp = wc_get_product($cid);
        if (!$cp) continue;
        $img_id = $cp->get_image_id();
        if (!$img_id) continue;
        $path = get_attached_file($img_id);
        if ($path && file_exists($path)) {
            $images[] = $path;
        }
    }

    $count = count($images);
    if ($count < 1) return array('error' => 'Nėra nuotraukų');

    // Grid layout
    $layouts = array(
        1 => array(1, 1, 0),
        2 => array(2, 1, 0),
        3 => array(3, 1, 0),
        4 => array(2, 2, 0),
        5 => array(3, 2, 2),
        6 => array(3, 2, 0),
        7 => array(4, 2, 3),
        8 => array(4, 2, 0),
        9 => array(3, 3, 0),
        10 => array(4, 3, 2),
        11 => array(4, 3, 3),
        12 => array(4, 3, 0),
    );

    $layout = $layouts[$count] ?? array((int)ceil(sqrt($count)), (int)ceil($count / ceil(sqrt($count))), 0);
    $cols = $layout[0];
    $rows = $layout[1];
    $last_row = $layout[2];

    $canvas_w = $cols * $tile_size + ($cols - 1) * $gap + $padding * 2;
    $canvas_h = $rows * $tile_size + ($rows - 1) * $gap + $padding * 2;

    $canvas = imagecreatetruecolor($canvas_w, $canvas_h);
    $bg = imagecolorallocate($canvas, $bg_color_rgb[0], $bg_color_rgb[1], $bg_color_rgb[2]);
    imagefilledrectangle($canvas, 0, 0, $canvas_w - 1, $canvas_h - 1, $bg);
    $tile_bg = imagecolorallocate($canvas, $tile_bg_rgb[0], $tile_bg_rgb[1], $tile_bg_rgb[2]);

    foreach ($images as $i => $path) {
        $row = intval($i / $cols);
        $col = $i % $cols;

        // Paskutinės eilutės centravimas
        if ($last_row > 0 && $row === $rows - 1) {
            $items_in_row = $last_row;
            $row_width = $items_in_row * $tile_size + ($items_in_row - 1) * $gap;
            $row_pad = ($canvas_w - $row_width) / 2;
            $x = (int)$row_pad + $col * ($tile_size + $gap);
        } else {
            $x = $padding + $col * ($tile_size + $gap);
        }
        $y = $padding + $row * ($tile_size + $gap);

        // Tile fonas
        imagefilledrectangle($canvas, $x, $y, $x + $tile_size - 1, $y + $tile_size - 1, $tile_bg);

        // Produkto nuotrauka
        $info = getimagesize($path);
        if (!$info) continue;
        $mime = $info['mime'];
        $src = null;
        if ($mime === 'image/jpeg') $src = imagecreatefromjpeg($path);
        elseif ($mime === 'image/png') $src = imagecreatefrompng($path);
        elseif ($mime === 'image/webp' && function_exists('imagecreatefromwebp')) $src = imagecreatefromwebp($path);
        if (!$src) continue;

        $sw = imagesx($src);
        $sh = imagesy($src);
        $ratio = min($tile_size / $sw, $tile_size / $sh);
        $nw = (int)($sw * $ratio);
        $nh = (int)($sh * $ratio);
        $dx = $x + (int)(($tile_size - $nw) / 2);
        $dy = $y + (int)(($tile_size - $nh) / 2);

        imagecopyresampled($canvas, $src, $dx, $dy, 0, 0, $nw, $nh, $sw, $sh);
        imagedestroy($src);
    }

    // Išsaugom į temp failą
    $upload_dir = wp_upload_dir();
    $filename = 'rink-composition-' . $product_id . '-' . time() . '.jpg';
    $filepath = $upload_dir['path'] . '/' . $filename;
    imagejpeg($canvas, $filepath, 88);
    imagedestroy($canvas);

    if (!file_exists($filepath)) return array('error' => 'Nepavyko išsaugoti kompozicijos');

    // Įkeliame kaip WP media
    $filetype = wp_check_filetype($filename, null);
    $attachment = array(
        'guid' => $upload_dir['url'] . '/' . $filename,
        'post_mime_type' => $filetype['type'],
        'post_title' => sanitize_file_name(pathinfo($filename, PATHINFO_FILENAME)),
        'post_content' => '',
        'post_status' => 'inherit',
    );
    $attach_id = wp_insert_attachment($attachment, $filepath, $product_id);
    if (is_wp_error($attach_id)) return array('error' => 'Media klaida: ' . $attach_id->get_error_message());

    require_once ABSPATH . 'wp-admin/includes/image.php';
    $meta = wp_generate_attachment_metadata($attach_id, $filepath);
    wp_update_attachment_metadata($attach_id, $meta);

    // Priskiriam kaip featured image
    set_post_thumbnail($product_id, $attach_id);

    return array('media_id' => $attach_id, 'url' => wp_get_attachment_url($attach_id));
}

