    </div>

    <script>
    (function(){
        var components = [];
        var nonce = '<?php echo esc_js($nonce); ?>';
        var ajaxurl = '<?php echo esc_js(admin_url('admin-ajax.php')); ?>';
        var searchTimer = null;

        var searchInput = document.getElementById('bf-search');
        var searchResults = document.getElementById('bf-search-results');
        var compContainer = document.getElementById('bf-components');
        var createBtn = document.getElementById('bf-create');
        var statusEl = document.getElementById('bf-status');
        var summaryEl = document.getElementById('bf-summary');
        var summaryText = document.getElementById('bf-summary-text');
        var resultEl = document.getElementById('bf-result');

        // Produktų paieška
        searchInput.addEventListener('input', function() {
            clearTimeout(searchTimer);
            var val = this.value.trim();
            if (val.length < 2) { searchResults.style.display = 'none'; return; }
            searchTimer = setTimeout(function() {
                fetch(ajaxurl + '?action=petshop_search_products&nonce=' + nonce + '&term=' + encodeURIComponent(val))
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        searchResults.innerHTML = '';
                        if (!data.length) {
                            searchResults.innerHTML = '<div style="padding:8px;color:#999;">Nerasta</div>';
                            searchResults.style.display = 'block';
                            return;
                        }
                        data.forEach(function(p) {
                            var already = components.some(function(c) { return c.id === p.id; });
                            var div = document.createElement('div');
                            div.style.cssText = 'padding:8px 12px;cursor:pointer;border-bottom:1px solid #eee;display:flex;align-items:center;gap:8px;' + (already ? 'opacity:0.4;' : '');
                            div.innerHTML = (p.image ? '<img src="'+p.image+'" style="width:32px;height:32px;object-fit:contain;border-radius:4px;">' : '')
                                + '<div style="flex:1;"><div style="font-size:13px;">'+p.text+'</div>'
                                + '<div style="font-size:11px;color:#666;">Kaina: '+p.price+' € | Likutis: '+(p.stock !== null ? p.stock : '∞')+'</div></div>';
                            if (!already) {
                                div.addEventListener('click', function() {
                                    addComponent(p);
                                    searchResults.style.display = 'none';
                                    searchInput.value = '';
                                });
                                div.addEventListener('mouseenter', function() { this.style.background = '#f5f5f5'; });
                                div.addEventListener('mouseleave', function() { this.style.background = ''; });
                            }
                            searchResults.appendChild(div);
                        });
                        searchResults.style.display = 'block';
                    });
            }, 300);
        });

        document.addEventListener('click', function(e) {
            if (!searchResults.contains(e.target) && e.target !== searchInput) {
                searchResults.style.display = 'none';
            }
        });

        function addComponent(product) {
            components.push({ id: product.id, name: product.text, price: parseFloat(product.price), qty: 1, stock: product.stock, image: product.image });
            renderComponents();
        }

        function renderComponents() {
            compContainer.innerHTML = '';
            if (!components.length) {
                compContainer.innerHTML = '<p style="color:#999;">Dar nepridėta komponentų. Naudokite paiešką aukščiau.</p>';
                summaryEl.style.display = 'none';
                createBtn.disabled = true;
                return;
            }

            var table = document.createElement('table');
            table.className = 'widefat striped';
            table.innerHTML = '<thead><tr><th style="width:40px;"></th><th>Produktas</th><th style="width:80px;">Kaina</th><th style="width:80px;">Kiekis</th><th style="width:90px;">Suma</th><th style="width:40px;"></th></tr></thead>';
            var tbody = document.createElement('tbody');

            var totalQty = 0, totalPrice = 0;

            components.forEach(function(c, i) {
                var tr = document.createElement('tr');
                var subtotal = (c.price * c.qty).toFixed(2);
                totalQty += c.qty;
                totalPrice += c.price * c.qty;
                tr.innerHTML = '<td>' + (c.image ? '<img src="'+c.image+'" style="width:32px;height:32px;object-fit:contain;">' : '') + '</td>'
                    + '<td style="font-size:13px;">' + c.name + '</td>'
                    + '<td>' + c.price.toFixed(2) + ' €</td>'
                    + '<td><input type="number" min="1" max="99" value="'+c.qty+'" data-idx="'+i+'" class="bf-qty-input" style="width:60px;"></td>'
                    + '<td><strong>' + subtotal + ' €</strong></td>'
                    + '<td><button type="button" class="button bf-remove-btn" data-idx="'+i+'" title="Pašalinti" style="color:#c00;">✕</button></td>';
                tbody.appendChild(tr);
            });
            table.appendChild(tbody);
            compContainer.appendChild(table);

            // Event listeners
            compContainer.querySelectorAll('.bf-qty-input').forEach(function(inp) {
                inp.addEventListener('change', function() {
                    var idx = parseInt(this.dataset.idx);
                    components[idx].qty = Math.max(1, parseInt(this.value) || 1);
                    renderComponents();
                });
            });
            compContainer.querySelectorAll('.bf-remove-btn').forEach(function(btn) {
                btn.addEventListener('click', function() {
                    components.splice(parseInt(this.dataset.idx), 1);
                    renderComponents();
                });
            });

            // Santrauka
            var bundlePrice = parseFloat(document.getElementById('bf-price').value) || 0;
            var savingsText = '';
            if (bundlePrice > 0 && totalPrice > bundlePrice) {
                var savings = totalPrice - bundlePrice;
                var pct = Math.round((savings / totalPrice) * 100);
                savingsText = ' | Sutaupymas: ' + savings.toFixed(2) + ' € (' + pct + '%)';
            }
            summaryText.innerHTML = components.length + ' unikalūs komponentai, ' + totalQty + ' vnt. iš viso | Atskirai: ' + totalPrice.toFixed(2) + ' €' + savingsText;
            summaryEl.style.display = 'block';

            // Mygtukas
            var title = document.getElementById('bf-title').value.trim();
            var sku = document.getElementById('bf-sku').value.trim();
            createBtn.disabled = !(title && sku && bundlePrice > 0 && components.length > 0);
        }

        // Perskaičiuojam kai keičiasi kaina
        document.getElementById('bf-price').addEventListener('input', renderComponents);
        document.getElementById('bf-title').addEventListener('input', renderComponents);
        document.getElementById('bf-sku').addEventListener('input', renderComponents);

        // SUKŪRIMAS
        createBtn.addEventListener('click', function() {
            createBtn.disabled = true;
            statusEl.textContent = 'Kuriama... (gali užtrukti iki 30 sek.)';
            statusEl.style.color = '#666';
            resultEl.style.display = 'none';

            var bundleData = {
                title: document.getElementById('bf-title').value.trim(),
                sku: document.getElementById('bf-sku').value.trim(),
                category: document.getElementById('bf-category').value,
                price: parseFloat(document.getElementById('bf-price').value),
                short_description: document.getElementById('bf-short-desc').value.trim(),
                components: components.map(function(c) { return { id: c.id, qty: c.qty }; })
            };

            var formData = new FormData();
            formData.append('action', 'petshop_create_bundle');
            formData.append('nonce', nonce);
            formData.append('bundle_data', JSON.stringify(bundleData));

            fetch(ajaxurl, { method: 'POST', body: formData })
                .then(function(r) { return r.json(); })
                .then(function(res) {
                    if (res.success) {
                        var d = res.data;
                        statusEl.textContent = '';
                        resultEl.style.display = 'block';
                        resultEl.innerHTML = '<h3 style="color: #2e7d32; margin-top:0;">✅ Rinkinys sukurtas!</h3>'
                            + '<p>Produkto ID: <strong>' + d.product_id + '</strong> | Vnt: ' + d.total_qty + '</p>'
                            + '<p><a href="' + d.view_url + '" target="_blank" class="button">🔗 Peržiūrėti puslapyje</a> '
                            + '<a href="' + d.edit_url + '" class="button">✏️ Redaguoti admin</a></p>'
                            + (d.composition && d.composition.url ? '<p>Kompozicija: <img src="'+d.composition.url+'" style="max-width:300px;margin-top:8px;border-radius:8px;display:block;"></p>' : '');
                    } else {
                        statusEl.textContent = '❌ Klaida: ' + (res.data || 'Nežinoma klaida');
                        statusEl.style.color = '#c00';
                        createBtn.disabled = false;
                    }
                })
                .catch(function(err) {
                    statusEl.textContent = '❌ Tinklo klaida: ' + err.message;
                    statusEl.style.color = '#c00';
                    createBtn.disabled = false;
                });
        });

        renderComponents();
    })();
    </script>
    <?php
}
